import java.io.*;class Main{static int[] solve(int[][] edges){int n=edges.length;int[] parentOf=new int[n+1];int[] candA=null,candB=null;for(int[] e:edges){int u=e[0],v=e[1];if(parentOf[v]==0)parentOf[v]=u;else{candA=new int[]{parentOf[v],v};candB=new int[]{u,v};break;}}int[] parent=new int[n+1];for(int i=0;i<=n;i++)parent[i]=i;java.util.function.IntUnaryOperator find=new java.util.function.IntUnaryOperator(){public int applyAsInt(int x){while(parent[x]!=x){parent[x]=parent[parent[x]];x=parent[x];}return x;}};for(int[] e:edges){if(candB!=null&&e[0]==candB[0]&&e[1]==candB[1])continue;int ra=find.applyAsInt(e[0]),rb=find.applyAsInt(e[1]);if(ra==rb)return candA!=null?candA:e;parent[rb]=ra;}return candB;}static String fmt(int[] e){return "["+e[0]+","+e[1]+"]";}public static void main(String[] a)throws Exception{String text=new String(System.in.readAllBytes()).trim();if(text.isEmpty())return;String[] d=text.split("\\s+");int idx=0,t=Integer.parseInt(d[idx++]);StringBuilder out=new StringBuilder();for(int tc=0;tc<t;tc++){int n=Integer.parseInt(d[idx++]);int[][] edges=new int[n][2];for(int i=0;i<n;i++){edges[i][0]=Integer.parseInt(d[idx++]);edges[i][1]=Integer.parseInt(d[idx++]);}if(tc>0)out.append("\n\n");out.append(fmt(solve(edges)));}System.out.print(out);}}
